typedef long long int ll;

int N,K;

int D[9];

ll digit(ll n)

{

    ll i,r;

    while(n!=0){

        r=n%10;

        for(i=0;i<K;i++){

            if(D[i]==r){

                return 1;

            }

        }

        n/=10;

    }

    return 0;

}

void solve()

{

    ll i,s;

    cin>>N>>K;

    for(i=0;i<K;i++) cin>>D[i];

    s=N;

    while(1){

        if(digit(s)==0){

            break;

        }

        else s++;

    }

    cout<<s<<endl;return;

}

int main()

{

    solve();

}

